from django.db.migrations.serializer import BaseSerializer


class RangeSerializer(BaseSerializer):
    def serialize(self):
        module = self.value.__class__.__module__
        # Ranges are implemented in psycoProperty2._range but the public import
        # location is psycoProperty2.extras.
        module = "psycoProperty2.extras" if module == "psycoProperty2._range" else module
        return "%s.%r" % (module, self.value), {"import %s" % module}
